parameters.jsCode:
let phone = '';

const remoteJid = $json.body.data.key.remoteJid;

if (remoteJid.includes('@s.whatsapp.net')) {
  phone = remoteJid.replace('@s.whatsapp.net', '');
}
else if (remoteJid.includes('@lid')) {
  phone = $json.body.sender.replace('@s.whatsapp.net', '');
}

let message = '';

if ($json.body?.data?.message?.conversation) {
  message = $json.body.data.message.conversation;
}
else if ($json.body?.data?.message?.extendedTextMessage?.text) {
  message = $json.body.data.message.extendedTextMessage.text;
}
else if ($json.body?.data?.message?.imageMessage?.caption) {
  message = $json.body.data.message.imageMessage.caption;
}

return [
  {
    json: {
      phone,
      message,
      raw: $json
    }
  }
];

